286: PlannedStmt *
287: planner(Query *parse, const char *query_string, int cursorOptions,
288: 		ParamListInfo boundParams)
289: {
290: 	PlannedStmt *result;
291: 
292: 	if (planner_hook)
293: 		result = (*planner_hook) (parse, query_string, cursorOptions, boundParams);
294: 	else
295: 		result = standard_planner(parse, query_string, cursorOptions, boundParams);
